-- SQL para popular a tabela technicians no Supabase
-- Gerado automaticamente a partir de BaseTecnicos.xlsx + Databricks
-- Execute no Supabase SQL Editor

ON CONFLICT (name) DO UPDATE SET
  phone = EXCLUDED.phone,
  region = EXCLUDED.region,
  supervisor_name = EXCLUDED.supervisor_name,
  databricks_name = EXCLUDED.databricks_name,
  databricks_id = EXCLUDED.databricks_id,
  updated_at = NOW();